const tokenData = $input.first().json;

// Extraer el access token y refresh token
return [{
  json: {
    access_token: tokenData.access_token,
    refresh_token: tokenData.refresh_token,
    token_type: tokenData.token_type,
    expires_in: tokenData.expires_in
  }
}];

// Obtener movimientos pendientes
const pendingMoves = $input.all();

if (pendingMoves.length === 0) {
  console.log('✅ No hay movimientos pendientes para procesar');
  return [];
}

console.log(`📦 Movimientos pendientes: ${pendingMoves.length}`);

const accessToken = $('Extract_Token').first().json.access_token;
const DELAY_MS = 500;

// Primero necesitamos obtener el mapeo de SKU a Item ID
// Para esto, hacemos una búsqueda de todos los items activos y pausados

const userId = '2303729344'; // Tu user ID
const allItemIds = [];

// Función para obtener items
async function getItems(status) {
  let items = [];
  let offset = 0;
  let hasMore = true;

  while (hasMore) {
    const url = `https://api.mercadolibre.com/users/${userId}/items/search?status=${status}&offset=${offset}&limit=100`;

    try {
      const response = await this.helpers.httpRequest({
        method: 'GET',
        url: url,
        headers: { 'Authorization': `Bearer ${accessToken}` },
        json: true
      });

      const results = response.results || [];
      items = items.concat(results);

      if (results.length < 100) {
        hasMore = false;
      } else {
        offset += 100;
        await new Promise(resolve => setTimeout(resolve, DELAY_MS));
      }
    } catch (error) {
      console.error(`Error obteniendo items ${status}:`, error.message);
      hasMore = false;
    }
  }

  return items;
}

// Obtener items activos y pausados
console.log('🔍 Obteniendo lista de items...');
const activeItems = await getItems.call(this, 'active');
const pausedItems = await getItems.call(this, 'paused');
const allIds = [...activeItems, ...pausedItems];

console.log(`📋 Total items encontrados: ${allIds.length}`);

// Obtener detalles de cada item (en batches)
const BATCH_SIZE = 20;
const itemDetails = [];

for (let i = 0; i < allIds.length; i += BATCH_SIZE) {
  const batch = allIds.slice(i, i + BATCH_SIZE);

  console.log(`📊 Obteniendo detalles: batch ${Math.floor(i/BATCH_SIZE) + 1}/${Math.ceil(allIds.length/BATCH_SIZE)}`);

  const promises = batch.map(async (itemId) => {
    try {
      const response = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://api.mercadolibre.com/items/${itemId}`,
        headers: { 'Authorization': `Bearer ${accessToken}` },
        json: true
      });
      return response;
    } catch (error) {
      console.error(`Error obteniendo item ${itemId}:`, error.message);
      return null;
    }
  });

  const results = await Promise.all(promises);
  itemDetails.push(...results.filter(r => r !== null));

  await new Promise(resolve => setTimeout(resolve, DELAY_MS));
}

console.log(`✅ Detalles obtenidos: ${itemDetails.length} items`);

// Función para extraer SKU
function extractSKU(itemData) {
  if (itemData.attributes && Array.isArray(itemData.attributes)) {
    const skuAttr = itemData.attributes.find(attr => 
      attr.id === 'SELLER_SKU' && attr.value_name
    );

    if (skuAttr && skuAttr.value_name) {
      return skuAttr.value_name;
    }
  }

  return itemData.seller_custom_field || itemData.id;
}

// Crear mapeo SKU -> Item Details
const skuToItem = {};
itemDetails.forEach(item => {
  const sku = extractSKU(item);
  skuToItem[sku] = {
    item_id: item.id,
    title: item.title,
    current_stock: item.available_quantity || 0,
    status: item.status,
    listing_type: item.listing_type_id
  };
});

console.log(`📋 Mapeo SKU creado: ${Object.keys(skuToItem).length} SKUs`);

// Combinar movimientos pendientes con info de items
const output = [];

pendingMoves.forEach(move => {
  const moveSku = move.json.sku;
  const moveQty = parseInt(move.json.cantidad) || 0;
  const moveType = move.json.tipo || 'COMPRA';
  const rowNumber = move.json.row_number; // n8n agrega esto automáticamente

  const itemInfo = skuToItem[moveSku];

  if (!itemInfo) {
    console.log(`⚠️ SKU ${moveSku} no encontrado en MercadoLibre`);
    output.push({
      json: {
        ...move.json,
        error: 'SKU no encontrado en MercadoLibre',
        procesado: 'ERROR'
      }
    });
  } else {
    const newStock = itemInfo.current_stock + moveQty;

    console.log(`📦 SKU ${moveSku}: Stock actual ${itemInfo.current_stock} + ${moveQty} = ${newStock}`);

    output.push({
      json: {
        ...move.json,
        item_id: itemInfo.item_id,
        stock_anterior: itemInfo.current_stock,
        stock_nuevo: newStock,
        title: itemInfo.title,
        status: itemInfo.status
      }
    });
  }
});

console.log(`✅ Movimientos preparados para actualizar: ${output.length}`);

return output;

const movesToProcess = $input.all();

if (movesToProcess.length === 0) {
  console.log('✅ No hay movimientos para procesar');
  return [];
}

console.log(`📦 Movimientos a procesar: ${movesToProcess.length}`);

const accessToken = $('Extract_Token').first().json.access_token;
const DELAY_MS = 1000; // 1 segundo entre actualizaciones para evitar rate limit

const results = [];

for (let i = 0; i < movesToProcess.length; i++) {
  const move = movesToProcess[i];
  const data = move.json;

  // Si ya tiene error, no procesar
  if (data.error) {
    results.push(move);
    continue;
  }

  console.log(`\n🔄 Procesando ${i + 1}/${movesToProcess.length}: SKU ${data.sku}`);
  console.log(`   Item ID: ${data.item_id}`);
  console.log(`   Stock: ${data.stock_anterior} → ${data.stock_nuevo}`);

  try {
    // Actualizar stock en MercadoLibre
    const response = await this.helpers.httpRequest({
      method: 'PUT',
      url: `https://api.mercadolibre.com/items/${data.item_id}`,
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Content-Type': 'application/json'
      },
      body: {
        available_quantity: data.stock_nuevo
      },
      json: true
    });

    console.log(`   ✅ Stock actualizado exitosamente`);

    results.push({
      json: {
        ...data,
        procesado: 'SI',
        fecha_procesado: new Date().toISOString(),
        ml_response: 'OK'
      }
    });

  } catch (error) {
    console.error(`   ❌ Error actualizando stock:`, error.message);

    results.push({
      json: {
        ...data,
        procesado: 'ERROR',
        fecha_procesado: new Date().toISOString(),
        error: error.message
      }
    });
  }

  // Delay entre actualizaciones
  if (i < movesToProcess.length - 1) {
    await new Promise(resolve => setTimeout(resolve, DELAY_MS));
  }
}

console.log(`\n📊 Resumen:`);
const successful = results.filter(r => r.json.procesado === 'SI').length;
const errors = results.filter(r => r.json.procesado === 'ERROR').length;
console.log(`   ✅ Exitosos: ${successful}`);
console.log(`   ❌ Errores: ${errors}`);

return results;
